type Listener = () => void;

export function createPriceStore() {
  let prices: Record<string, number> = {};
  const skuListeners = new Map<string, Set<Listener>>();

  function subscribe(sku: string, cb: Listener) {
    let set = skuListeners.get(sku);
    if (!set) { set = new Set(); skuListeners.set(sku, set); }
    set.add(cb);
    return () => set!.delete(cb);
  }

  function getPrice(sku: string) { return prices[sku]; }

  function applyTick(updates: Record<string, number>) {
    for (const sku of Object.keys(updates)) {
      if (prices[sku] === updates[sku]) continue;
      prices[sku] = updates[sku];
      skuListeners.get(sku)?.forEach(cb => cb());
    }
  }
  return { subscribe, getPrice, applyTick };
}

export type PriceStore = ReturnType<typeof createPriceStore>;

