export type Quote = { step:number; age:number; smoker:boolean; plan:string; dependents:string[] };
export type Action =
  | { type:'SET_FIELD'; field:keyof Quote; value:any }
  | { type:'NEXT' } | { type:'BACK' } | { type:'HYDRATE'; quote:Quote };

export const initialQuote: Quote = { step:0, age:0, smoker:false, plan:'', dependents:[] };

function eligible(q: Quote): boolean {
  if (q.plan === 'catastrophic' && q.age >= 30) return false;
  return true;
}

export function quoteReducer(state: Quote, a: Action): Quote {
  switch (a.type) {
    case 'SET_FIELD': {
      const next = { ...state, [a.field]: a.value };
      return eligible(next) ? next : state; // reject invalid combo at the source
    }
    case 'NEXT': return state.step < 8 ? { ...state, step: state.step + 1 } : state;
    case 'BACK': return state.step > 0 ? { ...state, step: state.step - 1 } : state;
    case 'HYDRATE': return a.quote;
    default: return state;
  }
}

