}

type Snap = { liked:boolean; count:number };
type Listener = () => void;

export function createLikeStore(api = fetch) {
  const state = new Map<string, Snap>();
  const confirmed = new Map<string, Snap>();
  const inflight = new Map<string, AbortController>();
  const gen = new Map<string, number>();
  const listeners = new Map<string, Set<Listener>>();

  const notify = (id:string) => listeners.get(id)?.forEach(l => l());
  const get = (id:string, seed:Snap) => state.get(id) ?? seed;

  function subscribe(id:string, cb:Listener) {
    let s = listeners.get(id); if (!s){ s=new Set(); listeners.set(id,s);} s.add(cb);
    return () => s!.delete(cb);
  }

  async function toggle(id:string, seed:Snap) {
    const cur = state.get(id) ?? seed;
    if (!confirmed.has(id)) confirmed.set(id, cur);
    const optimistic = { liked: !cur.liked, count: cur.count + (cur.liked ? -1 : 1) };
    state.set(id, optimistic); notify(id);
    inflight.get(id)?.abort();              // coalesce rapid toggles
    const ctrl = new AbortController(); inflight.set(id, ctrl);
    const myGen = (gen.get(id) ?? 0) + 1; gen.set(id, myGen);
    try {
      const res = await api(`/api/posts/${id}/like`, { method:'POST', body: JSON.stringify({ liked: optimistic.liked }), signal: ctrl.signal });
      const data: Snap = await res.json();
      if (gen.get(id) === myGen) { state.set(id, data); confirmed.set(id, data); notify(id); }
    } catch (e:any) {
      if (e.name === 'AbortError') return;     // superseded toggle, ignore
      state.set(id, confirmed.get(id)!); notify(id); // rollback
    } finally { if (inflight.get(id) === ctrl) inflight.delete(id); }
  }
  return { subscribe, get, toggle };
}

