export function CheckoutSummary() {
  const { lines, promo, address } = useCart();
  const subtotal = lines.reduce((s, l) => s + l.price * l.qty, 0);
  const discount = promo ? subtotal * 0.1 : 0;            // promo formula copy #1
  const tax = (subtotal - discount) * taxRate(address.state);
  const total = subtotal - discount + tax + shipping(lines);
  return <div>Total: {total}</div>;
}

export type Line = { sku:string; price:number; qty:number };
export type CartInput = { lines: Line[]; promo: string | null; state: string };
export type TaxFn = (state:string) => number;

export function selectTotals(input: CartInput, taxFn: TaxFn) {
  const subtotal = input.lines.reduce((s,l) => s + l.price * l.qty, 0);
  const discount = input.promo ? Math.round(subtotal * 0.1) : 0;
  const taxable = subtotal - discount;
  const tax = Math.round(taxable * taxFn(input.state));
  const ship = input.lines.length === 0 ? 0 : (subtotal > 5000 ? 0 : 599);
  return { subtotal, discount, tax, ship, total: subtotal - discount + tax + ship };
}

