export function UploadItem({ file }) {
  const [isUploading, setUploading] = useState(false);
  const [isError, setError] = useState(false);
  const [isDone, setDone] = useState(false);
  const [progress, setProgress] = useState(0);
  async function start() {
    setUploading(true); setError(false);
    try { await put(file, p => setProgress(p)); setDone(true); }
    catch { setError(true); }
    finally { setUploading(false); }
  }
  // retry can fire even when isDone is true
  return <>{isDone && <Check/>}{isError && <ErrorBanner onRetry={start}/>}</>;
}

export type Status =
  | { tag:'idle' }
  | { tag:'uploading'; progress:number }
  | { tag:'error'; message:string }
  | { tag:'done'; url:string };
export type Ev =
  | { type:'START' } | { type:'PROGRESS'; p:number }
  | { type:'SUCCESS'; url:string } | { type:'FAIL'; message:string }
  | { type:'RETRY' } | { type:'RESET' };

export function reduce(s: Status, e: Ev): Status {
  switch (s.tag) {
    case 'idle': return e.type==='START' ? { tag:'uploading', progress:0 } : s;
    case 'uploading':
      if (e.type==='PROGRESS') return { tag:'uploading', progress:e.p };
      if (e.type==='SUCCESS') return { tag:'done', url:e.url };
      if (e.type==='FAIL') return { tag:'error', message:e.message };
      return s;
    case 'error': return e.type==='RETRY' ? { tag:'uploading', progress:0 } : s;
    case 'done': return e.type==='RESET' ? { tag:'idle' } : s; // no RETRY from done
    default: return s;
  }
}

import { useReducer, useEffect } from 'react';
import { reduce, Status } from './uploadMachine';
import { loadStatus, saveStatus } from './sessionStore';

export function useUpload(sessionId: string) {
  const [status, dispatch] = useReducer(reduce, undefined as any, () => loadStatus(sessionId) ?? { tag:'idle' } as Status);
  useEffect(() => { saveStatus(sessionId, status); }, [sessionId, status]);
  return [status, dispatch] as const;
}

import { useUpload } from './useUpload';

export function UploadItem({ sessionId }: { sessionId:string }) {
  const [status, dispatch] = useUpload(sessionId);
  switch (status.tag) {
    case 'idle': return <button onClick={() => dispatch({ type:'START' })}>Upload</button>;
    case 'uploading': return <Progress value={status.progress} />;
    case 'error': return <ErrorBanner message={status.message} onRetry={() => dispatch({ type:'RETRY' })} />;
    case 'done': return <Check url={status.url} />;
  }
}

export function useSlice(selector) {
  const store = useReduxStore();
  const [slice, setSlice] = useState(() => selector(store.getState()));
  useEffect(() => store.subscribe(() => setSlice(selector(store.getState()))), []);
  return slice; // reads via setState async -> can tear during concurrent render
}

import { useSyncExternalStore, useRef } from 'react';
import { useReduxStore } from './store';

export function useReduxSelector<T>(selector:(s:any)=>T, isEqual=(a:T,b:T)=>a===b) {
  const store = useReduxStore();
  const last = useRef<{ v:T } | null>(null);
  const getSnapshot = () => {
    const next = selector(store.getState());
    if (last.current && isEqual(last.current.v, next)) return last.current.v;
    last.current = { v: next };
    return next;
  };
  return useSyncExternalStore(store.subscribe, getSnapshot, getSnapshot);
}

import { useReduxSelector } from './useReduxSelector';
