export function shallowEqual<T extends Record<string,any>>(a:T,b:T){
  const ka=Object.keys(a), kb=Object.keys(b);
  if(ka.length!==kb.length) return false;
  for(const k of ka) if(a[k]!==b[k]) return false;
  return true;
}

