type Rule = { deps:string[]; validate:(v:any,all:any)=>string|null };
export const schema: Record<string,Rule> = {
  ssn: { deps:['country'], validate:(v,all)=> all.country==='US' && !/^\d{9}$/.test(v) ? 'SSN must be 9 digits' : null },
  taxId: { deps:['entityType'], validate:(v,all)=> all.entityType==='llc' && !/^\d{2}-\d{7}$/.test(v) ? 'EIN format' : null },
};
export const fieldsDependingOn = (field:string) =>
  Object.entries(schema).filter(([,r]) => r.deps.includes(field)).map(([k]) => k);

import { schema, fieldsDependingOn } from './schema';
export type FormState = { values:Record<string,any>; errors:Record<string,string|null> };
export type Action = { type:'SET_FIELD'; field:string; value:any } | { type:'MERGE_ERRORS'; errors:Record<string,string> };

export function formReducer(s: FormState, a: Action): FormState {
  if (a.type==='MERGE_ERRORS') return { ...s, errors: { ...s.errors, ...a.errors } };
  const values = { ...s.values, [a.field]: a.value };
  const errors = { ...s.errors };
  for (const f of [a.field, ...fieldsDependingOn(a.field)]) {
    const r = schema[f]; if (r) errors[f] = r.validate(values[f], values);
  }
  return { values, errors };
}
export const selectCanSubmit = (s: FormState) => Object.values(s.errors).every(e => !e) && Object.keys(schema).every(k => s.values[k] != null);

import { useReducer } from 'react';
import { formReducer, selectCanSubmit } from './formReducer';

