export type Card = { id:string; columnId:string; rank:number };
export type Action =
  | { type:'MOVE_OPTIMISTIC'; id:string; columnId:string; rank:number; snapshotId:string }
  | { type:'RECONCILE'; id:string; rank:number }
  | { type:'REVERT'; snapshotId:string };

export function boardReducer(cards: Card[], a: Action, snaps: Map<string,Card[]>): Card[] {
  switch (a.type) {
    case 'MOVE_OPTIMISTIC':
      snaps.set(a.snapshotId, cards);
      return cards.map(c => c.id===a.id ? { ...c, columnId:a.columnId, rank:a.rank } : c);
    case 'RECONCILE':
      return cards.map(c => c.id===a.id ? { ...c, rank:a.rank } : c);
    case 'REVERT':
      return snaps.get(a.snapshotId) ?? cards;
    default: return cards;
  }
}
export const between = (a:number,b:number) => (a+b)/2;

import { useReducer, useRef } from 'react';
import { boardReducer, between } from './boardReducer';

export function useReorder(initial) {
  const snaps = useRef(new Map());
  const [cards, raw] = useReducer((s,a)=>boardReducer(s,a,snaps.current), initial);
  async function move(id:string, columnId:string, prevRank:number, nextRank:number) {
    const snapshotId = crypto.randomUUID();
    raw({ type:'MOVE_OPTIMISTIC', id, columnId, rank: between(prevRank,nextRank), snapshotId });
    try {
      const r = await fetch(`/api/cards/${id}`, { method:'PATCH', body: JSON.stringify({ columnId, prevRank, nextRank }) });
      const { rank } = await r.json();
      raw({ type:'RECONCILE', id, rank });
    } catch { raw({ type:'REVERT', snapshotId }); }
  }
  return { cards, move };
}

import { useReorder } from './useReorder';

export function Column({ initial }: { initial: any }) {
  const { cards, move } = useReorder(initial);
  return <List cards={cards} onDrop={(id, columnId, prev, next) => move(id, columnId, prev, next)} />;
}

