export function Canvas() {
  const [doc, setDoc] = useState(initialDoc);
  const [history, setHistory] = useState([initialDoc]);
  const [ptr, setPtr] = useState(0);
  function apply(next) {
    const snap = structuredClone(next);           // ~4MB clone per edit
    setHistory(h => [...h.slice(0, ptr+1), snap]);
    setPtr(p => p+1); setDoc(next);
  }
  function undo() { setPtr(p => Math.max(0,p-1)); setDoc(history[ptr-1]); }
  return <Stage doc={doc} onEdit={apply} />;
}

export type Command = {
  key?: string; // coalesce key
  apply: (doc:Doc)=>Doc;
  invert: (doc:Doc)=>Doc;
};
export const moveShape = (id:string, dx:number, dy:number): Command => ({
  key: `move:${id}`,
  apply: d => ({ ...d, shapes: d.shapes.map(s => s.id===id ? { ...s, x:s.x+dx, y:s.y+dy } : s) }),
  invert: d => ({ ...d, shapes: d.shapes.map(s => s.id===id ? { ...s, x:s.x-dx, y:s.y-dy } : s) }),
});
export type Doc = { shapes: { id:string; x:number; y:number }[] };

import { Command, Doc } from './commands';
export type State = { doc: Doc; past: Command[]; future: Command[] };
export type Action = { type:'APPLY'; cmd:Command } | { type:'UNDO' } | { type:'REDO' };
const CAP = 200;
export function historyReducer(s: State, a: Action): State {
  switch (a.type) {
    case 'APPLY': {
      const last = s.past[s.past.length-1];
      if (last && a.cmd.key && last.key === a.cmd.key) {
        // coalesce: replace last command's net effect
        const doc = a.cmd.apply(s.doc);
        return { doc, past: s.past, future: [] };
      }
      const doc = a.cmd.apply(s.doc);
      const past = [...s.past, a.cmd].slice(-CAP);
      return { doc, past, future: [] };
    }
    case 'UNDO': {
      const cmd = s.past[s.past.length-1]; if (!cmd) return s;
      return { doc: cmd.invert(s.doc), past: s.past.slice(0,-1), future: [cmd, ...s.future] };
    }
    case 'REDO': {
      const cmd = s.future[0]; if (!cmd) return s;
      return { doc: cmd.apply(s.doc), past: [...s.past, cmd], future: s.future.slice(1) };
    }
    default: return s;
  }
}

import { useReducer } from 'react';
import { historyReducer } from './historyReducer';
import { moveShape } from './commands';

export function Canvas({ initialDoc }: { initialDoc:any }) {
  const [state, dispatch] = useReducer(historyReducer, { doc: initialDoc, past: [], future: [] });
  return <Stage doc={state.doc}
    onMove={(id,dx,dy) => dispatch({ type:'APPLY', cmd: moveShape(id,dx,dy) })}
    onUndo={() => dispatch({ type:'UNDO' })} onRedo={() => dispatch({ type:'REDO' })} />;
}

