export type View = { filters:Record<string,string>; sort:{key:string;dir:'asc'|'desc'}; page:number };
export type Action =
  | { type:'SET_FILTER'; key:string; value:string } | { type:'SET_SORT'; key:string }
  | { type:'SET_PAGE'; page:number } | { type:'HYDRATE'; view:View };
export const defaultView: View = { filters:{}, sort:{key:'date',dir:'desc'}, page:1 };
export function viewReducer(s: View, a: Action): View {
  switch (a.type) {
    case 'SET_FILTER': return { ...s, filters: { ...s.filters, [a.key]: a.value }, page: 1 };
    case 'SET_SORT': return { ...s, sort: { key:a.key, dir: s.sort.key===a.key && s.sort.dir==='asc' ? 'desc':'asc' } };
    case 'SET_PAGE': return { ...s, page: a.page };
    case 'HYDRATE': return a.view;
    default: return s;
  }
}

import { View, defaultView } from './viewReducer';
export function viewToParams(v: View): string {
  const p = new URLSearchParams();
  Object.entries(v.filters).forEach(([k,val]) => p.set(`f_${k}`, val));
  p.set('sort', `${v.sort.key}:${v.sort.dir}`); p.set('page', String(v.page));
  return p.toString();
}
export function paramsToView(qs: string): View {
  const p = new URLSearchParams(qs);
  const filters: Record<string,string> = {};
  for (const [k,val] of p) if (k.startsWith('f_')) filters[k.slice(2)] = val;
  const [sk='date', sd='desc'] = (p.get('sort')||'').split(':');
  const page = Math.max(1, parseInt(p.get('page')||'1',10) || 1); // coerce invalid
  return { filters, sort: { key:sk, dir: sd==='asc'?'asc':'desc' }, page };
}

import { useReducer, useEffect, useRef } from 'react';
