export function useUrlView() {
  const [view, dispatch] = useReducer(viewReducer, undefined as any, () => paramsToView(location.search));
  const t = useRef<any>();
  useEffect(() => {
    clearTimeout(t.current);
    t.current = setTimeout(() => history.replaceState(null,'', '?'+viewToParams(view)), 200); // debounced
  }, [view]);
  useEffect(() => {
    const onPop = () => dispatch({ type:'HYDRATE', view: paramsToView(location.search) });
    window.addEventListener('popstate', onPop); return () => window.removeEventListener('popstate', onPop);
  }, []);
  return [view, dispatch] as const;
}

