// Inspector and Minimap each call useEntities() -> separate copies

type Listener = () => void;
export function createEntityStore() {
  let version = -1;
  let entities: Record<string, any> = {};
  const listeners = new Set<Listener>();
  function applyFrame(v:number, next:Record<string,any>) {
    if (v <= version) return;            // drop out-of-order / stale frames
    version = v; entities = next;
    listeners.forEach(l => l());
  }
  return {
    applyFrame,
    subscribe: (cb:Listener) => { listeners.add(cb); return () => listeners.delete(cb); },
    getEntity: (id:string) => entities[id],
    getAll: () => entities,
    getVersion: () => version,
  };
}

import { useSyncExternalStore, useContext, useRef } from 'react';
import { EntityStoreContext } from './ctx';
export function useEntity(id:string) {
  const store = useContext(EntityStoreContext);
  const last = useRef<any>(); 
  return useSyncExternalStore(store.subscribe, () => {
    const e = store.getEntity(id);
    if (last.current && shallowEq(last.current, e)) return last.current;
    return (last.current = e);
  });
}
export function usePositions() {
  const store = useContext(EntityStoreContext);
  return useSyncExternalStore(store.subscribe, store.getVersion); // minimap re-renders per version only
}
function shallowEq(a:any,b:any){ if(!a||!b) return a===b; for(const k in a) if(a[k]!==b[k]) return false; return true; }

import { EntityStore } from './entityStore';
export function wireWorker(worker: Worker, store: ReturnType<typeof EntityStore>) {
  worker.onmessage = (e) => {
    const { version, entities } = e.data; // parsed off the critical render path
    store.applyFrame(version, entities);
  };
}

