type Mode = 'light'|'dark';
type Listener = () => void;
export function createThemeStore() {
  let mode: Mode = (localStorage.getItem('theme') as Mode) || (matchMedia('(prefers-color-scheme: dark)').matches ? 'dark':'light');
  const listeners = new Set<Listener>();
  function setMode(m: Mode) {
    mode = m; document.documentElement.dataset.theme = m;
    localStorage.setItem('theme', m); listeners.forEach(l => l());
  }
  document.documentElement.dataset.theme = mode;
  return { setMode, getMode: () => mode, subscribe: (cb:Listener) => { listeners.add(cb); return () => listeners.delete(cb); } };
}

