export function Conversation({ convId }) {
  const [messages, setMessages] = useState([]);
  useEffect(() => {
    socket.on('msg', m => setMessages(ms => [...ms, m])); // no dedupe -> reconnect duplicates
  }, []);
  async function send(text) {
    const ack = await socket.emitWithAck('send', { text }); // 500ms wait before display
    setMessages(ms => [...ms, ack.message]);
  }
  return <Thread messages={messages} onSend={send} />;
}

type Msg = { id:string; tempId?:string; seq:number; text:string; pending?:boolean };
type Listener = () => void;
export function createConversationStore() {
  const byConv = new Map<string, Map<string, Msg>>();
  const listeners = new Map<string, Set<Listener>>();
  const map = (c:string) => byConv.get(c) ?? (byConv.set(c, new Map()), byConv.get(c)!);
  const notify = (c:string) => listeners.get(c)?.forEach(l => l());
  function optimisticInsert(c:string, m:Msg) { map(c).set(m.tempId!, { ...m, pending:true }); notify(c); }
  function reconcile(c:string, tempId:string, server:Msg) { const mm=map(c); mm.delete(tempId); mm.set(server.id, server); notify(c); }
  function upsertById(c:string, m:Msg) { map(c).set(m.id, m); notify(c); }       // dedupe by id
  function snapshot(c:string) { return [...map(c).values()].sort((a,b)=>a.seq-b.seq); }
  return { optimisticInsert, reconcile, upsertById, snapshot,
    subscribe:(c:string,cb:Listener)=>{ let s=listeners.get(c); if(!s){s=new Set();listeners.set(c,s);} s.add(cb); return ()=>s!.delete(cb); } };
}

import { useSyncExternalStore, useContext, useMemo } from 'react';
import { ConvStoreContext } from './ctx';
export function useConversation(convId:string) {
  const store = useContext(ConvStoreContext);
  const messages = useSyncExternalStore(cb => store.subscribe(convId, cb), () => store.snapshot(convId), () => []);
  const send = (text:string) => {
    const tempId = crypto.randomUUID();
    store.optimisticInsert(convId, { id:tempId, tempId, seq:Number.MAX_SAFE_INTEGER, text });
    socket.emitWithAck('send', { tempId, text }).then(ack => store.reconcile(convId, tempId, ack.message));
  };
  return { messages, send };
}

export function wireSocket(socket:any, store:any) {
  socket.on('msg', (m:any) => store.upsertById(m.convId, m));     // dedupe on replay
  socket.on('reconnect', () => socket.emit('replay'));
}

export function PayForm({ amount }) {
  const [submitting, setSubmitting] = useState(false);
  const [succeeded, setSucceeded] = useState(false);
  async function pay() {
    setSubmitting(true);
    const key = crypto.randomUUID();          // NEW key every attempt, even on retry
    const res = await charge(amount, key);    // 3DS can pause here for seconds
    if (res.ok) setSucceeded(true); else setSubmitting(false);
  }
  return <button disabled={submitting || succeeded} onClick={pay}>Pay</button>;
}

export type PayState =
  | { tag:'idle' }
  | { tag:'authorizing'; key:string }
  | { tag:'challenged'; key:string; redirectUrl:string }
  | { tag:'capturing'; key:string }
  | { tag:'done'; key:string }
  | { tag:'failed'; key:string; message:string };
export type Ev =
  | { type:'START'; key:string } | { type:'CHALLENGE'; redirectUrl:string }
  | { type:'RESUME' } | { type:'CAPTURED' } | { type:'FAIL'; message:string } | { type:'RETRY' };

export function payReducer(s: PayState, e: Ev): PayState {
  switch (s.tag) {
    case 'idle': return e.type==='START' ? { tag:'authorizing', key:e.key } : s;
    case 'authorizing':
      if (e.type==='CHALLENGE') return { tag:'challenged', key:s.key, redirectUrl:e.redirectUrl };
      if (e.type==='CAPTURED') return { tag:'done', key:s.key };
      if (e.type==='FAIL') return { tag:'failed', key:s.key, message:e.message };
      return s; // START ignored while authorizing -> no double charge
    case 'challenged': return e.type==='RESUME' ? { tag:'capturing', key:s.key } : s;
    case 'capturing':
      if (e.type==='CAPTURED') return { tag:'done', key:s.key };
      if (e.type==='FAIL') return { tag:'failed', key:s.key, message:e.message };
      return s;
    case 'failed': return e.type==='RETRY' ? { tag:'authorizing', key:s.key } : s; // reuse key
    case 'done': return s; // terminal
    default: return s;
  }
}

import { useReducer, useEffect } from 'react';
import { payReducer, PayState } from './payMachine';
const KEY='pay-intent';
export function usePayment(intentId:string) {
  const [state, dispatch] = useReducer(payReducer, undefined as any, () => {
    const raw = sessionStorage.getItem(`${KEY}:${intentId}`); return raw ? JSON.parse(raw) as PayState : { tag:'idle' };
  });
  useEffect(() => { sessionStorage.setItem(`${KEY}:${intentId}`, JSON.stringify(state)); }, [intentId, state]);
  return [state, dispatch] as const;
}

import { usePayment } from './usePayment';
export function PayForm({ intentId, amount }: { intentId:string; amount:number }) {
  const [state, dispatch] = usePayment(intentId);
  async function pay() {
    if (state.tag !== 'idle' && state.tag !== 'failed') return;
    const key = state.tag==='failed' ? state.key : crypto.randomUUID();
    dispatch(state.tag==='failed' ? { type:'RETRY' } : { type:'START', key });
    const res = await charge(amount, key);
    res.challenge ? dispatch({ type:'CHALLENGE', redirectUrl:res.url }) : res.ok ? dispatch({ type:'CAPTURED' }) : dispatch({ type:'FAIL', message:res.error });
  }
  return <button disabled={state.tag==='authorizing'||state.tag==='capturing'||state.tag==='done'} onClick={pay}>Pay</button>;
}

