type Toast = { id:string; groupKey?:string; message:string; ttl:number };
type Listener = () => void;
export function createToastStore(max=4) {
  let visible: Toast[] = []; let queue: Toast[] = [];
  const timers = new Map<string, any>(); const listeners = new Set<Listener>();
  const notify = () => listeners.forEach(l => l());
  function schedule(t:Toast) { timers.set(t.id, setTimeout(() => dismiss(t.id), t.ttl)); }
  function push(t:Toast) {
    if (t.groupKey) { const ex = visible.find(v => v.groupKey===t.groupKey); if (ex) { ex.message = t.message; notify(); return; } } // coalesce
    if (visible.length < max) { visible = [...visible, t]; schedule(t); } else queue.push(t);
    notify();
  }
  function dismiss(id:string) {
    clearTimeout(timers.get(id)); timers.delete(id);
    visible = visible.filter(v => v.id!==id);
    const next = queue.shift(); if (next) { visible = [...visible, next]; schedule(next); }
    notify();
  }
  return { push, dismiss, getVisible: () => visible, subscribe:(cb:Listener)=>{ listeners.add(cb); return ()=>listeners.delete(cb);} };
}

