export type Sel = { selected: Set<string>; anchor: string | null };
export type Action =
  | { type:'TOGGLE'; id:string } | { type:'RANGE'; id:string; ordered:string[] }
  | { type:'ALL'; ids:string[] } | { type:'CLEAR' };
export function selectionReducer(s: Sel, a: Action): Sel {
  switch (a.type) {
    case 'TOGGLE': { const n = new Set(s.selected); n.has(a.id)?n.delete(a.id):n.add(a.id); return { selected:n, anchor:a.id }; }
    case 'RANGE': {
      if (!s.anchor) return selectionReducer(s, { type:'TOGGLE', id:a.id });
      const i = a.ordered.indexOf(s.anchor), j = a.ordered.indexOf(a.id);
      const [lo,hi] = i<j?[i,j]:[j,i]; const n = new Set(s.selected);
      for (let k=lo;k<=hi;k++) n.add(a.ordered[k]); return { selected:n, anchor:s.anchor };
    }
    case 'ALL': return { selected:new Set(a.ids), anchor:s.anchor };
    case 'CLEAR': return { selected:new Set(), anchor:null };
    default: return s;
  }
}

