type Listener = () => void;
export function createPresenceStore() {
  const presence = new Map<string, number>();  // userId -> lastSeen
  const typing = new Map<string, number>();     // userId -> lastTypingAt
  const listeners = new Set<Listener>();
  const notify = () => listeners.forEach(l => l());
  function ping(userId:string) { presence.set(userId, Date.now()); notify(); }
  function setTyping(userId:string) { typing.set(userId, Date.now()); notify(); }
  setInterval(() => { const now=Date.now(); let changed=false; for (const [u,t] of typing) if (now-t>3000){ typing.delete(u); changed=true; } if (changed) notify(); }, 1000);
  return { ping, setTyping, snapshot: () => ({ online:[...presence.keys()], typing:[...typing.keys()] }), subscribe:(cb:Listener)=>{ listeners.add(cb); return ()=>listeners.delete(cb);} };
}

