type Listener = () => void;
export function createFlagStore(defs:Record<string,{deps:string[]; evaluate:(u:any,c:any)=>boolean}>) {
  let user:any = null, ctx:any = {};
  const cache = new Map<string, boolean>();
  const overrides = new Map<string, boolean>();
  const listeners = new Set<Listener>();
  const notify = () => listeners.forEach(l=>l());
  function get(key:string):boolean {
    if (overrides.has(key)) return overrides.get(key)!;
    if (cache.has(key)) return cache.get(key)!;
    const v = defs[key].evaluate(user, ctx); cache.set(key, v); return v;
  }
  function setContext(next:any) {
    const changedDims = Object.keys(next).filter(k => next[k] !== ctx[k]);
    ctx = next;
    for (const [key, def] of Object.entries(defs)) if (def.deps.some(d => changedDims.includes(d))) cache.delete(key);
    notify();
  }
  function override(key:string, v:boolean) { overrides.set(key, v); notify(); }
  return { get, setUser:(u:any)=>{ user=u; cache.clear(); notify(); }, setContext, override, subscribe:(cb:Listener)=>{ listeners.add(cb); return ()=>listeners.delete(cb);} };
}

