type Listener = () => void;
export function createClockStore() {
  let now = Date.now(); let timer:any = null; let refs = 0;
  const listeners = new Set<Listener>();
  const tick = () => { now = Date.now(); listeners.forEach(l=>l()); };
  const start = () => { if (!timer && !document.hidden) timer = setInterval(tick, 1000); };
  const stop = () => { if (timer) { clearInterval(timer); timer=null; } };
  document.addEventListener('visibilitychange', () => document.hidden ? stop() : (tick(), start()));
  return { getNow: () => now, subscribe:(cb:Listener)=>{ listeners.add(cb); if(++refs===1) start(); return ()=>{ listeners.delete(cb); if(--refs===0) stop(); }; } };
}

import { useSyncExternalStore, useContext, useRef } from 'react';
import { ClockCtx } from './ctx';
export function useCountdown(endsAt:number) {
  const store = useContext(ClockCtx);
  const lastSec = useRef(-1);
  const remaining = useSyncExternalStore(store.subscribe, () => {
    const sec = Math.max(0, Math.floor((endsAt - store.getNow())/1000));
    if (sec === lastSec.current) return lastSec.current; // equality: same second -> no re-render
    return (lastSec.current = sec);
  });
  return { remaining, ended: remaining === 0 };
}

