type Listener = () => void;
export function createOrderStore() {
  let seq = -1; const orders = new Map<string,any>(); const listeners = new Set<Listener>();
  function apply(eventSeq:number, ev:any) {
    if (eventSeq <= seq) return;        // ignore stale/out-of-order
    seq = eventSeq;
    if (ev.type==='created' || ev.type==='updated') orders.set(ev.order.id, ev.order);
    if (ev.type==='removed') orders.delete(ev.order.id);
    listeners.forEach(l=>l());
  }
  function markReadyOptimistic(id:string) { const o = orders.get(id); if (o) { orders.set(id, { ...o, status:'ready' }); listeners.forEach(l=>l()); } }
  return { apply, markReadyOptimistic, forStation:(s:string)=>[...orders.values()].filter(o=>o.station===s), subscribe:(cb:Listener)=>{ listeners.add(cb); return ()=>listeners.delete(cb);} };
}

