type Listener = () => void;
const KEY = 'session';
export function createAuthStore() {
  const listeners = new Set<Listener>();
  let cached = read();
  function read() { try { return JSON.parse(localStorage.getItem(KEY) || 'null'); } catch { return null; } }
  window.addEventListener('storage', (e) => { if (e.key === KEY) { cached = read(); listeners.forEach(l=>l()); } });
  return {
    getSnapshot: () => cached,
    getServerSnapshot: () => null,
    setSession: (s:any) => { localStorage.setItem(KEY, JSON.stringify(s)); cached = s; listeners.forEach(l=>l()); },
    logout: () => { localStorage.removeItem(KEY); cached = null; listeners.forEach(l=>l()); },
    subscribe: (cb:Listener) => { listeners.add(cb); return () => listeners.delete(cb); },
  };
}

