export function sheetReducer(state, action) {
  let recalc; // shared local reused across cases -> bugs
  switch (action.type) {
    case 'EDIT_CELL': recalc = recompute(state.cells, action); return { ...state, cells: recalc };
    case 'SELECT': return { ...state, selection: action.range };
    case 'PASTE': /* 120 lines mutating cells, clipboard, history */ return { ...state };
    case 'UNDO': /* reaches into every slice */ return { ...state };
    // ...40 more cases
  }
}

export function cellsReducer(cells:any, action:any) {
  switch (action.type) {
    case 'EDIT_CELL': return recompute(cells, action);
    case 'SET_CELLS': return action.cells; // used by paste coordinator
    default: return cells;
  }
}
export function selectionReducer(sel:any, action:any) {
