import { cellsReducer, selectionReducer, clipboardReducer } from './slices';
import { applyPaste } from './paste';
export function rootReducer(state:any, action:any) {
  if (action.type === 'PASTE') return applyPaste(state, action); // explicit cross-slice coordination
  return {
    cells: cellsReducer(state.cells, action),
    selection: selectionReducer(state.selection, action),
    clipboard: clipboardReducer(state.clipboard, action),
    history: state.history,
  };
}

import { cellsReducer } from './slices';
export function applyPaste(state:any, action:any) {
  const before = state.cells;
  const cells = cellsReducer(state.cells, { type:'SET_CELLS', cells: mergePaste(state.cells, state.clipboard, state.selection) });
  const history = [...state.history, { type:'paste', before }].slice(-200);
  return { ...state, cells, history };
}

export function noteReducer(state, action) {
  switch (action.type) {
    case 'EDIT': return { ...state, content: action.content };
    case 'SAVED': return { ...state, content: action.content }; // blind overwrite, no version
    default: return state;
  }
}
// save(): PUT /note { content } -> ignores server version

export type NoteState =
  | { tag:'clean'; version:number; content:string }
  | { tag:'dirty'; version:number; content:string }
  | { tag:'conflict'; version:number; local:string; server:string };
export type Action =
  | { type:'EDIT'; content:string } | { type:'SAVED'; version:number; content:string }
  | { type:'CONFLICT'; serverVersion:number; serverContent:string } | { type:'RESOLVE'; content:string };
export function noteReducer(s: NoteState, a: Action): NoteState {
  switch (a.type) {
    case 'EDIT': return s.tag==='conflict' ? { ...s, local:a.content } as any : { tag:'dirty', version:s.version, content:a.content };
    case 'SAVED': return { tag:'clean', version:a.version, content:a.content };
    case 'CONFLICT': return { tag:'conflict', version:a.serverVersion, local:(s as any).content ?? (s as any).local, server:a.serverContent };
    case 'RESOLVE': return { tag:'dirty', version:s.version, content:a.content };
    default: return s;
  }
}

import { useReducer } from 'react';
import { noteReducer, NoteState } from './noteReducer';
export function useNote(initial: NoteState) {
  const [state, dispatch] = useReducer(noteReducer, initial);
  async function save() {
    if (state.tag !== 'dirty') return;
    const res = await fetch('/api/note', { method:'PUT', body: JSON.stringify({ baseVersion: state.version, content: state.content }) });
    if (res.status === 409) { const srv = await res.json(); dispatch({ type:'CONFLICT', serverVersion: srv.version, serverContent: srv.content }); }
    else { const ok = await res.json(); dispatch({ type:'SAVED', version: ok.version, content: ok.content }); }
  }
  return { state, dispatch, save };
}

import { useNote } from './useNote';
export function NoteEditor({ initial }: { initial:any }) {
  const { state, dispatch, save } = useNote(initial);
  if (state.tag === 'conflict') return <MergeView local={state.local} server={state.server} onResolve={c => dispatch({ type:'RESOLVE', content:c })} />;
  return <><textarea value={state.content} onChange={e => dispatch({ type:'EDIT', content:e.target.value })} /><button onClick={save}>Save</button></>;
}

export const MapContext = createContext(null);
export function MapProvider({ children }) {
  const [viewport, setViewport] = useState(initialView);
  const [markers, setMarkers] = useState([]);
  const [hoveredId, setHoveredId] = useState(null);
  const value = { viewport, setViewport, markers, hoveredId, setHoveredId };
  return <MapContext.Provider value={value}>{children}</MapContext.Provider>;
}

import { createContext, useContext, useState, useSyncExternalStore, useRef } from 'react';
const HoverCtx = createContext<any>(null);
export function HoverProvider({ children }:{children:any}) {
  const [hoveredId, setHoveredId] = useState<string|null>(null);
  return <HoverCtx.Provider value={{ hoveredId, setHoveredId }}>{children}</HoverCtx.Provider>;
}
export function useSetHover() { return useContext(HoverCtx).setHoveredId; }
export function useIsHovered(id:string) {
  const { hoveredId } = useContext(HoverCtx);
  return hoveredId === id; // with split provider, only entered/exited markers re-evaluate to a changed value
}

import { createContext, useContext, useState } from 'react';
const Ctx = createContext<any>(null);
export function MarkersProvider({ children }:{children:any}) {
  const [markers, setMarkers] = useState<any[]>([]);
  return <Ctx.Provider value={markers}>{children}</Ctx.Provider>;
}
export const useMarkers = () => useContext(Ctx);

import { memo } from 'react';
import { useIsHovered, useSetHover } from './HoverContext';
export const Marker = memo(function Marker({ m }: { m:any }) {
  const hovered = useIsHovered(m.id);
  const setHover = useSetHover();
  return <Pin lat={m.lat} lng={m.lng} active={hovered} onMouseEnter={() => setHover(m.id)} onMouseLeave={() => setHover(null)} />;
}, (a,b) => a.m === b.m);

export function JobList() {
  const [pages, setPages] = useState([]);
  const [page, setPage] = useState(1);
  async function loadMore() {
    const data = await fetch(`/api/jobs?page=${page}`).then(r=>r.json()); // offset drifts
    setPages(p => [...p, ...data.jobs]); setPage(p => p+1);
  }
  return <InfiniteScroll onMore={loadMore}>{pages.map(j => <JobCard key={j.id} job={j} />)}</InfiniteScroll>;
}

import { useInfiniteQuery } from '@tanstack/react-query';
export function useJobs(filters:any) {
  return useInfiniteQuery({
    queryKey: ['jobs', filters],
    queryFn: ({ pageParam }) => fetch(`/api/jobs?cursor=${pageParam ?? ''}&${qs(filters)}`).then(r=>r.json()),
    initialPageParam: '',
    getNextPageParam: (last) => last.nextCursor ?? undefined,
    staleTime: 5*60_000,
    select: (data) => {
      const seen = new Set<string>(); const items:any[] = [];
      for (const p of data.pages) for (const j of p.jobs) if (!seen.has(j.id)) { seen.add(j.id); items.push(j); } // dedupe by id
      return items;
    },
  });
}

import { useJobs } from './useJobs';
export function JobList({ filters }: { filters:any }) {
  const { data: jobs = [], fetchNextPage, hasNextPage } = useJobs(filters);
  return <InfiniteScroll onMore={() => hasNextPage && fetchNextPage()}>{jobs.map(j => <JobCard key={j.id} job={j} />)}</InfiniteScroll>;
}

export function useScrollRestoration(key:string) {
  // save scrollTop on unmount, restore on mount keyed by the list query
  return { onSave:(y:number)=>sessionStorage.setItem(`scroll:${key}`, String(y)), restore:()=>+(sessionStorage.getItem(`scroll:${key}`)||0) };
}
